import{_ as e,o as t,c as s,ag as d}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Creating Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Creating-Cards.md","filePath":"Creating-Cards.md","lastUpdated":1772690052000}'),i={name:"Creating-Cards.md"};function n(r,a,o,l,c,p){return t(),s("div",null,[...a[0]||(a[0]=[d(`<h1 id="creating-cards" tabindex="-1">Creating Cards <a class="header-anchor" href="#creating-cards" aria-label="Permalink to &quot;Creating Cards&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="creation-paths" tabindex="-1">Creation Paths <a class="header-anchor" href="#creation-paths" aria-label="Permalink to &quot;Creation Paths&quot;">​</a></h2><p>You can create cards with guided modals or by writing fields directly in markdown.</p><p>Modals are usually faster for <a href="./Image-Occlusion">Image Occlusion</a> and <a href="./Multiple-Choice-Questions">Multiple Choice Questions</a>.</p><h2 id="modal-method" tabindex="-1">Modal Method <a class="header-anchor" href="#modal-method" aria-label="Permalink to &quot;Modal Method&quot;">​</a></h2><ol><li>Right-click in a note, or open the command palette (<code>Cmd/Ctrl+P</code>).</li><li>Choose an <strong>Add flashcard</strong> option.</li><li>Fill in the fields and select <strong>Save</strong>.</li></ol><p>LearnKit inserts the card block at your cursor.</p><h2 id="markdown-method" tabindex="-1">Markdown Method <a class="header-anchor" href="#markdown-method" aria-label="Permalink to &quot;Markdown Method&quot;">​</a></h2><p>Card fields use the delimiter <code>|</code> by default (or your configured <a href="./Custom-Delimiters">delimiter</a>).</p><table tabindex="0"><thead><tr><th>Field</th><th>Use</th><th>Required</th></tr></thead><tbody><tr><td><code>T</code></td><td>Title</td><td>No</td></tr><tr><td><code>Q</code></td><td>Basic question</td><td>Yes (basic)</td></tr><tr><td><code>A</code></td><td>Answer / correct option</td><td>Yes (basic, MCQ)</td></tr><tr><td><code>CQ</code></td><td>Cloze text</td><td>Yes (cloze)</td></tr><tr><td><code>MCQ</code></td><td>MCQ stem</td><td>Yes (MCQ)</td></tr><tr><td><code>O</code></td><td>Incorrect MCQ option</td><td>At least one (MCQ)</td></tr><tr><td><code>OQ</code></td><td>Ordered-question stem</td><td>Yes (ordered)</td></tr><tr><td><code>1</code>, <code>2</code>, <code>3</code>, ...</td><td>Ordered items (in correct sequence)</td><td>At least two (ordered)</td></tr><tr><td><code>I</code></td><td>Extra info</td><td>No</td></tr><tr><td><code>G</code></td><td>Groups (comma-separated)</td><td>No</td></tr></tbody></table><h3 id="minimal-examples" tabindex="-1">Minimal examples <a class="header-anchor" href="#minimal-examples" aria-label="Permalink to &quot;Minimal examples&quot;">​</a></h3><p><strong>Basic</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q | What is the capital of France? |</span></span>
<span class="line"><span>A | Paris |</span></span></code></pre></div><p><strong>Cloze</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CQ | The capital of France is &amp;#123;&amp;#123;c1::Paris&amp;#125;&amp;#125; |</span></span></code></pre></div><p><strong>MCQ</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MCQ | What is the capital of France? |</span></span>
<span class="line"><span>A | Paris |</span></span>
<span class="line"><span>O | London |</span></span>
<span class="line"><span>O | Berlin |</span></span></code></pre></div><p>See also:</p><ul><li><a href="./Basic-&amp;-Reversed-Cards">Basic &amp; Reversed Cards</a></li><li><a href="./Cloze-Cards">Cloze Cards</a></li><li><a href="./Image-Occlusion">Image Occlusion</a></li><li><a href="./Multiple-Choice-Questions">Multiple Choice Questions</a></li><li><a href="./Ordered-Questions">Ordered Questions</a></li><li><a href="./Flags">Flags</a></li></ul><h2 id="multi-line-fields" tabindex="-1">Multi-line fields <a class="header-anchor" href="#multi-line-fields" aria-label="Permalink to &quot;Multi-line fields&quot;">​</a></h2><p>Fields can span multiple lines. The field ends at the closing delimiter.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q | List three key features of X and include a diagram. |</span></span>
<span class="line"><span>A | Feature one</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Feature two</span></span>
<span class="line"><span></span></span>
<span class="line"><span>![diagram.png](./diagram.png.md) |</span></span>
<span class="line"><span>I | Keep answers structured. |</span></span></code></pre></div><h2 id="card-anchors" tabindex="-1">Card Anchors <a class="header-anchor" href="#card-anchors" aria-label="Permalink to &quot;Card Anchors&quot;">​</a></h2><p>After sync, each card block gets an anchor like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>^learnkit-#########</span></span></code></pre></div><p>Do not edit or delete this line. It links the card to its scheduling data. If you remove it, the card is treated as new on sync and previous progress is lost. See <a href="./Syncing">Syncing</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Cards">Cards</a></li><li><a href="./Editing-Cards">Editing Cards</a></li><li><a href="./Card-Formatting">Card Formatting</a></li></ul>`,29)])])}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
